const input = $input.first().json;
let data = null;
if (input.body && input.body.paid_charge_invoice_notification) {
  data = input.body.paid_charge_invoice_notification;
} else if (input.paid_charge_invoice_notification) {
  data = input.paid_charge_invoice_notification;
} else if (input.body && typeof input.body === 'object') {
  const notifKey = Object.keys(input.body).find(k => k.includes('notification'));
  data = notifKey ? input.body[notifKey] : input.body;
} else {
  const notifKey = Object.keys(input).find(k => k.includes('notification'));
  data = notifKey ? input[notifKey] : input;
}
if (!data) throw new Error('Could not find notification data. Check webhook output.');
const account = data.account || {};
const invoice = data.invoice || {};
let subIds = [];
if (invoice.subscription_ids) {
  const raw = invoice.subscription_ids.subscription_id || invoice.subscription_ids;
  subIds = Array.isArray(raw) ? raw : (raw ? [raw] : []);
}
const extractValue = (field) => {
  if (!field) return '0';
  if (typeof field === 'string') return field;
  if (field._ !== undefined) return field._;
  return '0';
};
const totalCents = parseInt(extractValue(invoice.total_in_cents), 10);
const subtotalCents = parseInt(extractValue(invoice.subtotal_in_cents), 10);
const taxCents = parseInt(extractValue(invoice.tax_in_cents), 10);
const createdAt = invoice.created_at?._ || invoice.created_at || '';
const closedAt = invoice.closed_at?._ || invoice.closed_at || '';
const collectionMethod = invoice.collection_method || '';
const invoiceNumber = extractValue(invoice.invoice_number);
const lineItems = invoice.line_items || [];
const creditPayments = invoice.credit_payments || [];
return [{
  json: {
    account_code: account.account_code || '',
    email: account.email || '',
    company_name: account.company_name || '',
    first_name: account.first_name || '',
    last_name: account.last_name || '',
    origin: invoice.origin || '',
    invoice_uuid: invoice.uuid || '',
    invoice_number: invoiceNumber,
    currency: invoice.currency || 'USD',
    total_cents: totalCents,
    total_display: '$' + (totalCents / 100).toFixed(2),
    subtotal_cents: subtotalCents,
    subtotal_display: '$' + (subtotalCents / 100).toFixed(2),
    tax_cents: taxCents,
    tax_display: '$' + (taxCents / 100).toFixed(2),
    created_at: createdAt,
    closed_at: closedAt,
    collection_method: collectionMethod,
    line_items: lineItems,
    credit_payments: creditPayments,
    subscription_id: subIds[0] || '',
  }
}];

const webhookData = $('Extract Fields').first().json;
const invoiceData = $('Recurly API - Get Invoice details1').first().json;
const sub = $input.first().json;

const planCode = (sub.plan && sub.plan.code) || '';
const planName = (sub.plan && sub.plan.name) || '';
const quantity = sub.quantity || 1;
const origin = webhookData.origin;

let customerType = 'UNKNOWN';
let totalCreditApplied = 0;

if (origin === 'purchase') {
  customerType = 'NEW_CUSTOMER';
} else if (origin === 'renewal') {
  customerType = 'RENEWAL';
} else if (origin === 'immediate_change') {
  const creditPayments = invoiceData.credit_payments || [];
  const upgradeCredits = creditPayments.filter(cp => 
    cp.amount > 0 && cp.original_invoice && cp.original_invoice.type === 'credit'
  );
  const hasCreditFromPriorPlan = upgradeCredits.length > 0;
  customerType = hasCreditFromPriorPlan ? 'UPGRADE_TO_ANNUAL' : 'EXPANSION';

  if (hasCreditFromPriorPlan) {
    totalCreditApplied = upgradeCredits.reduce((sum, cp) => sum + (cp.amount || 0), 0);
  }
}

// Net amount the customer actually paid (dollars, not cents — invoice API returns dollars)
const invoiceTotal = invoiceData.total || (webhookData.total_cents / 100);
const netAmount = invoiceTotal - totalCreditApplied;

return [{
  json: {
    ...webhookData,
    customer_type: customerType,
    plan_code: planCode,
    plan_name: planName,
    quantity: quantity,
    invoice_total: invoiceTotal,
    credit_applied: totalCreditApplied,
    net_amount: netAmount,
    net_amount_display: '$' + netAmount.toFixed(2),
    // Keep total_display as-is for other branches, but add a smart display
    // that shows net for upgrades, full total otherwise
    display_amount: customerType === 'UPGRADE_TO_ANNUAL' 
      ? '$' + netAmount.toFixed(2) 
      : webhookData.total_display,
  }
}];

const d = $input.first().json;
const typeConfig = {
  'NEW_CUSTOMER':      { emoji: '🆕', label: 'New Customer' },
  'EXPANSION':         { emoji: '📈', label: 'Expansion (More Seats)' },
  'UPGRADE_TO_ANNUAL': { emoji: '⬆️', label: 'Upgrade to Annual' },
  'RENEWAL':           { emoji: '🔄', label: 'Renewal' },
};
const config = typeConfig[d.customer_type] || { emoji: '💰', label: d.customer_type };

// Random celebration GIFs
const winGifs = [
  'https://media.giphy.com/media/l0MYt5jPR6QX5pnqM/giphy.gif',
  'https://media.giphy.com/media/3o7abKhOpu0NwenH3O/giphy.gif',
  'https://media.giphy.com/media/artj92V8o75VPL7AeQ/giphy.gif',
  'https://media.giphy.com/media/3oz8xAFtqoOUUrsh7W/giphy.gif',
  'https://media.giphy.com/media/l0HlBO7eyXzSZkJri/giphy.gif',
  'https://media.giphy.com/media/26u4cqiYI30juCOGY/giphy.gif',
  'https://media.giphy.com/media/3ornk57KwDXf81rjWM/giphy.gif',
  'https://media.giphy.com/media/l4JyOCNEfXxJKWyuY/giphy.gif',
];
const randomGif = winGifs[Math.floor(Math.random() * winGifs.length)];

const invoiceDate = d.created_at ? new Date(d.created_at).toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' }) : 'N/A';
const accountId = d.account_code.replace('organization-', '');
const accountUrl = `https://internal.katalon.com/accounts?accountId=${accountId}`;

const netDisplay = '$' + (d.net_amount || 0).toFixed(2);

const message = `${config.emoji} *${config.label}* | _Plan:_ ${d.plan_name || d.plan_code || 'N/A'} | _Amount:_ ${netDisplay} | _Seats:_ ${d.quantity} | _Date:_ ${invoiceDate} | _Account:_ <${accountUrl}|${d.account_code}>\n${randomGif}`;

const fallbackText = `${config.emoji} ${config.label}\nPlan: ${d.plan_name || d.plan_code || 'N/A'}\nAmount: ${netDisplay}\nSeats: ${d.quantity}\nDate: ${invoiceDate}\nAccount: ${accountUrl}\n${randomGif}`;

return [{
  json: {
    text: message,
    fallback_text: fallbackText,
    gif_url: randomGif,
  }
}];

